# tools/pre_sort_defects.py
"""Pre-sort UAT failures by likely severity before triage meeting."""
import json
from pathlib import Path

SAFETY_KEYWORDS = {
    "harmful", "pii", "legal", "incorrect advice", "leak",
    "discriminat", "personal data", "hallucinated citation",
}

results_dir = Path("uat-results")
failures = [
    json.loads(f.read_text())
    for f in results_dir.glob("*.json")
    if json.loads(f.read_text())["verdict"] != "PASS"
]

def likely_p0(r):
    return (
        r.get("category") in {"safety_policy", "regression"}
        or any(kw in r.get("notes", "").lower() for kw in SAFETY_KEYWORDS)
    )

p0_candidates = [r for r in failures if likely_p0(r)]
other_failures = [r for r in failures if not likely_p0(r)]

print("=== LIKELY P0 (review first) ===")
for r in sorted(p0_candidates, key=lambda x: x["scenario_id"]):
    print(f"  {r['scenario_id']}: {r.get('notes', '')}")

print(f"\n=== OTHER FAILURES ({len(other_failures)}) ===")
for r in sorted(other_failures, key=lambda x: x["weighted_total"]):
    print(f"  {r['scenario_id']}: score {r['weighted_total']:.2f}")

# tools/check_open_uat_defects.py
"""Report open UAT defects past their fix deadline."""
from datetime import date
import json
from pathlib import Path

today = date.today()
open_defects = []

for f in Path("defects").glob("*.yaml"):
    import yaml
    d = yaml.safe_load(f.read_text())
    if d.get("status") in {"open", "waived"}:
        expiry_str = (d.get("waiver") or {}).get("expires")
        if expiry_str:
            expiry = date.fromisoformat(expiry_str)
            days_remaining = (expiry - today).days
            open_defects.append({
                **d,
                "days_remaining": days_remaining,
                "overdue": days_remaining < 0,
            })

overdue = [d for d in open_defects if d["overdue"]]
expiring_soon = [d for d in open_defects if 0 <= d["days_remaining"] <= 14]

if overdue:
    print(f"OVERDUE ({len(overdue)} defects):")
    for d in overdue:
        print(f"  {d['id']} [{d['priority']}]: waiver expired {abs(d['days_remaining'])} days ago")

if expiring_soon:
    print(f"\nEXPIRING SOON ({len(expiring_soon)} defects):")
    for d in expiring_soon:
        print(f"  {d['id']} [{d['priority']}]: {d['days_remaining']} days until waiver expires")
